        if (json.status == "success" && json.data?.result?.size() > 0) {
            memPgFault = json.data.result[0].value[1] as Double
        }
    }
} catch (Exception e) {}

def memUsed = (memDomain > 0 && memAvail > 0) ? (memDomain - memAvail) : 0
def memPct = (memDomain > 0) ? ((memUsed / memDomain) * 100) : 0

println("memory_usage_percent:" + memPct)
println("memory_available_bytes:" + memAvail)
println("memory_used_bytes:" + memUsed)
println("memory_domain_bytes:" + memDomain)
